type Stage = 'ready' | 'deleting' | 'uploading' | 'done' | 'error';

interface UploadResult {
  deleted: number;
  uploaded: number;
  errors: string[];
  zoneCheck: { total: number; allPace: boolean };
}

export default function CleanUploadPage() {
  const [stage, setStage] = useState<Stage>('ready');
  const [result, setResult] = useState<UploadResult | null>(null);
  const [log, setLog] = useState<string[]>([]);

  const addLog = (msg: string) => setLog((prev) => [...prev, msg]);

  const handleRun = async () => {
    setStage('deleting');
    setLog([]);
    const errors: string[] = [];
    let deleted = 0;

    try {
      addLog('🔍 שלב 1: מחפש תבניות קיימות עם קטגוריה short_intervals או long_intervals...');

      const q1 = query(
        collection(db, COLLECTION),
        where('category', '==', 'short_intervals'),
      );
      const q2 = query(
        collection(db, COLLECTION),
        where('category', '==', 'long_intervals'),
      );

      const [snap1, snap2] = await Promise.all([getDocs(q1), getDocs(q2)]);
      const toDelete = [...snap1.docs, ...snap2.docs];
      addLog(`נמצאו ${toDelete.length} תבניות למחיקה (${snap1.size} short, ${snap2.size} long)`);

      for (const d of toDelete) {
        await deleteDoc(doc(db, COLLECTION, d.id));
        deleted++;
      }
      addLog(`✅ נמחקו ${deleted} תבניות`);

      setStage('uploading');
      addLog(`📤 שלב 2: מעלה ${TEMPLATES.length} תבניות חדשות...`);

      let uploaded = 0;
      let totalBlocks = 0;
      let allPace = true;

      for (let i = 0; i < TEMPLATES.length; i++) {
        const tpl = TEMPLATES[i];
        const { _comment, ...data } = tpl;

        const blocks = data.blocks as Record<string, unknown>[];
        for (const block of blocks) {
          totalBlocks++;
          if (block.blockMode !== 'pace') {
            allPace = false;
            errors.push(`${data.name}: block ${block.id} has blockMode="${block.blockMode}" instead of "pace"`);
          }
        }

        const ref = doc(collection(db, COLLECTION));
        await setDoc(ref, {
          ...data,
          createdAt: serverTimestamp(),
          updatedAt: serverTimestamp(),
        });
        uploaded++;
        if (uploaded % 6 === 0) addLog(`  ${uploaded}/${TEMPLATES.length} הועלו...`);
      }

      addLog(`✅ הועלו ${uploaded} תבניות חדשות (${totalBlocks} בלוקים)`);
      addLog(allPace ? '✅ כל הבלוקים blockMode="pace"' : '⚠️ חלק מהבלוקים לא pace!');

      setResult({ deleted, uploaded, errors, zoneCheck: { total: totalBlocks, allPace } });
      setStage('done');
    } catch (err: unknown) {
      const msg = err instanceof Error ? err.message : String(err);
      addLog(`❌ שגיאה: ${msg}`);
      errors.push(msg);
      setResult({ deleted, uploaded: 0, errors, zoneCheck: { total: 0, allPace: false } });
      setStage('error');
    }
  };

  return (
    <div dir="rtl" className="max-w-3xl mx-auto py-8 px-4">
      <h1 className="text-2xl font-black text-gray-900 mb-2">ניקוי והעלאת תבניות אינטרוולים</h1>
      <p className="text-sm text-gray-500 mb-6">
        מוחק את כל התבניות הקיימות עם קטגוריה <code className="bg-gray-100 px-1 rounded">short_intervals</code> / <code className="bg-gray-100 px-1 rounded">long_intervals</code> ומעלה 36 תבניות חדשות.
      </p>

      {stage === 'ready' && (
        <button
          onClick={handleRun}
          className="flex items-center gap-2 px-6 py-3 bg-red-600 text-white rounded-xl font-bold hover:bg-red-700 transition-colors"
        >
          <Trash2 size={18} /> מחק ישנות + העלה 36 חדשות
        </button>
      )}

      {(stage === 'deleting' || stage === 'uploading') && (
        <div className="flex items-center gap-3 text-blue-600 font-medium">
          <Loader2 size={20} className="animate-spin" />
          {stage === 'deleting' ? 'מוחק תבניות ישנות...' : 'מעלה תבניות חדשות...'}
        </div>
      )}

      {log.length > 0 && (
        <div className="mt-6 bg-gray-900 text-gray-100 p-4 rounded-xl text-sm font-mono space-y-1 max-h-80 overflow-auto">
          {log.map((l, i) => (
            <div key={i}>{l}</div>
          ))}
        </div>
      )}

      {stage === 'done' && result && (
        <div className="mt-6 bg-emerald-50 border border-emerald-300 rounded-xl p-5 space-y-3">
          <div className="flex items-center gap-2 text-emerald-700 font-bold text-lg">
            <CheckCircle size={22} /> הפעולה הושלמה בהצלחה
          </div>
          <div className="grid grid-cols-2 gap-3 text-sm">
            <div className="bg-white p-3 rounded-lg border">
              <div className="text-gray-500">נמחקו</div>
              <div className="text-2xl font-black text-red-600">{result.deleted}</div>
            </div>
            <div className="bg-white p-3 rounded-lg border">
              <div className="text-gray-500">הועלו</div>
              <div className="text-2xl font-black text-emerald-600">{result.uploaded}</div>
            </div>
            <div className="bg-white p-3 rounded-lg border">
              <div className="text-gray-500">בלוקים</div>
              <div className="text-2xl font-black text-blue-600">{result.zoneCheck.total}</div>
            </div>
            <div className="bg-white p-3 rounded-lg border">
              <div className="text-gray-500">blockMode=pace</div>
              <div className={`text-2xl font-black ${result.zoneCheck.allPace ? 'text-emerald-600' : 'text-red-600'}`}>
                {result.zoneCheck.allPace ? '✅' : '❌'}
              </div>
            </div>
          </div>
          {result.errors.length > 0 && (
            <div className="bg-amber-50 border border-amber-200 rounded-lg p-3">
              <div className="flex items-center gap-2 text-amber-700 font-bold mb-1">
                <AlertTriangle size={16} /> {result.errors.length} שגיאות
              </div>
              {result.errors.map((e, i) => (
                <div key={i} className="text-xs text-amber-600">{e}</div>
              ))}
            </div>
          )}
        </div>
      )}

      {stage === 'error' && (
        <div className="mt-6 bg-red-50 border border-red-300 rounded-xl p-5">
          <div className="flex items-center gap-2 text-red-700 font-bold">
            <AlertTriangle size={20} /> שגיאה בביצוע
          </div>
        </div>
      )}
    </div>
  );
}
